mapper.select:
/* roleInqyDao1010 : 권한 목록 조회 */ SELECT ROLE_CD , ROLE_NM , USE_YN , DISP_ORDER , REMARK FROM role WHERE 1=1
AND REGEXP_REPLACE(LOWER(ROLE_NM),'[^0-9가-힣A-Za-z]*','') LIKE '%'||REGEXP_REPLACE(LOWER(#{srchNm, jdbcType=VARCHAR}),'[^0-9가-힣A-Za-z]*','')||'%'
ORDER BY ROLE_CD

/* roleInqyDao4010 : 사용자 권한 목록 조회 */ SELECT DATA.* FROM ( SELECT EA.ROLE_CD , A.ROLE_NM , EA.EMP_IDX , E.EMP_NM , D.ORG_NM , EA.DISP_ORDER FROM EMP_ROLE EA LEFT OUTER JOIN EMP_INFO E ON E.EMP_IDX = EA.EMP_IDX LEFT OUTER JOIN role A ON A.ROLE_CD = EA.ROLE_CD AND A.USE_YN = 'Y' LEFT OUTER JOIN ORG D ON D.ORG_CD = E.ORG_CD WHERE 1=1
AND A.ROLE_CD = #{roleCd, jdbcType=VARCHAR}
) DATA ORDER BY DATA.EMP_NM, DATA.EMP_IDX

mapper.insert:
/* roleProcDao1010 : 권한 등록 처리 */
INSERT INTO role
(
			ROLE_CD
		,	ROLE_NM
		,	USE_YN
		,	DISP_ORDER
		,	REMARK
)
VALUES
(
		(SELECT 'ROLE_' || LPAD(NVL(MAX(SUBSTR(ROLE_CD,LENGTH(ROLE_CD)-3,LENGTH(ROLE_CD))),0) + 1,4,0) AS ROLE_CD FROM role)
	,	#{roleNm, jdbcType=VARCHAR}
	,	#{useYn, jdbcType=VARCHAR}
	,	(
			SELECT 
				NVL(MAX(DISP_ORDER),0) + 1 
			FROM role
		)
	,	#{remark, jdbcType=VARCHAR}
)

mapper.update:
/* roleProcDao1020 : 권한 수정 처리 */
UPDATE role
	SET		ROLE_NM = #{roleNm, jdbcType=VARCHAR}
		,	USE_YN = #{useYn, jdbcType=VARCHAR}
		,	REMARK = #{remark, jdbcType=VARCHAR}
WHERE ROLE_CD = #{roleCd, jdbcType=VARCHAR}

