/* roleProcDao1030 : 권한 삭제 처리 */
DELETE FROM role
	WHERE ROLE_CD = #{roleCd, jdbcType=VARCHAR}

/* roleProcDao1040 : 메뉴 권한 삭제 처리 */
DELETE FROM MENU_ROLE
	WHERE ROLE_CD = #{roleCd, jdbcType=VARCHAR}

